  1259→/* This will undo the client protection done by protectClient() */
  1260→void unprotectClient(client *c) {
  1261→    if (c->flags & CLIENT_PROTECTED) {
  1262→        c->flags &= ~CLIENT_PROTECTED;
  1263→        aeCreateFileEvent(server.el,c->fd,AE_READABLE,readQueryFromClient,c);
